package com.hospital.management.validation;import com.hospital.management.model.DoctorForm;import java.math.BigDecimal;import java.util.Set;import java.util.regex.Pattern;
/** Server-side validation for doctor creation and editing. */
public class DoctorValidator{private static final Pattern USER=Pattern.compile("[A-Za-z][A-Za-z0-9._-]{3,49}"),EMAIL=Pattern.compile("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$"),REG=Pattern.compile("[A-Za-z0-9/ -]{3,50}"),PHONE=Pattern.compile("\\+?[0-9][0-9 ()-]{6,19}"),NAME=Pattern.compile("[\\p{L}][\\p{L} .'-]*");public ValidationResult validateCreate(DoctorForm f){return validate(f,true);}public ValidationResult validateEdit(DoctorForm f){return validate(f,false);}private ValidationResult validate(DoctorForm f,boolean create){ValidationResult r=new ValidationResult();if(f.getUsername()==null||!USER.matcher(f.getUsername().trim()).matches())r.addError("username","Username must start with a letter and contain 4-50 permitted characters");if(f.getEmail()==null||f.getEmail().length()>150||!EMAIL.matcher(f.getEmail().trim()).matches())r.addError("email","Enter a valid email address");String p=f.getPassword();if(create||(p!=null&&!p.isBlank())){if(p==null||p.length()<8||p.length()>72||!p.matches(".*[A-Z].*")||!p.matches(".*[a-z].*")||!p.matches(".*\\d.*")||!p.matches(".*[^A-Za-z0-9].*"))r.addError("password","Password must be 8-72 characters with upper, lower, digit and special characters");else if(!p.equals(f.getConfirmPassword()))r.addError("confirmPassword","Passwords do not match");}if(f.getDepartmentId()==null||f.getDepartmentId()<=0)r.addError("departmentId","Select a department");if(f.getRegistrationNumber()==null||!REG.matcher(f.getRegistrationNumber().trim()).matches())r.addError("registrationNumber","Registration number must contain 3-50 permitted characters");text(r,"firstName",f.getFirstName(),2,100);text(r,"lastName",f.getLastName(),1,100);text(r,"specialization",f.getSpecialization(),2,150);text(r,"qualification",f.getQualification(),2,200);if(f.getPhone()==null||!PHONE.matcher(f.getPhone().trim()).matches())r.addError("phone","Enter a valid phone number");try{BigDecimal fee=new BigDecimal(f.getConsultationFee());if(fee.signum()<0||fee.compareTo(new BigDecimal("1000000"))>0||fee.scale()>2)throw new NumberFormatException();}catch(Exception e){r.addError("consultationFee","Fee must be 0-1,000,000 with at most two decimals");}if(!Set.of("ACTIVE","INACTIVE").contains(f.getStatus()))r.addError("status","Status must be ACTIVE or INACTIVE");return r;}private void text(ValidationResult r,String field,String v,int min,int max){int n=v==null?0:v.trim().length();if(n<min||n>max||((field.equals("firstName")||field.equals("lastName"))&&!NAME.matcher(v.trim()).matches()))r.addError(field,"Enter a valid "+field);}}
